#include<bits/stdc++.h>
using namespace std;
long long b[500010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long sum,lmax,rmax,ans;
    }t[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        long long ls=t[x].lson,rs=t[x].rson;
        t[x].sum=t[ls].sum+t[rs].sum;
        t[x].lmax=max(t[ls].lmax,t[ls].sum+t[rs].lmax);
        t[x].rmax=max(t[rs].rmax,t[rs].sum+t[ls].rmax);
        t[x].ans=max({t[ls].ans,t[rs].ans,t[ls].rmax+t[rs].lmax});
    }
    void pushup(node &x,node ls,node rs)
    {
        x.sum=ls.sum+rs.sum;
        x.lmax=max(ls.lmax,ls.sum+rs.lmax);
        x.rmax=max(rs.rmax,rs.sum+ls.rmax);
        x.ans=max({ls.ans,rs.ans,ls.rmax+rs.lmax});
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        if(l==r)
        {
            t[x].sum=t[x].lmax=t[x].rmax=t[x].ans=b[l];
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long v)
    {
        if(t[x].l>p||t[x].r<p)
        {
            return;
        }
        if(t[x].l==t[x].r)
        {
            t[x].sum=t[x].lmax=t[x].rmax=t[x].ans=v;
            return;
        }
        update(t[x].lson,p,v);
        update(t[x].rson,p,v);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        long long mid=(t[x].l+t[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    while(m--)
    {
        long long op,x,y;
        scanf("%lld%lld%lld",&op,&x,&y);
        if(op==1)
        {
            if(x>y)
            {
                swap(x,y);
            }
            printf("%lld\n",t.query(1,x,y).ans);
        }
        else
        {
            t.update(1,x,y);
        }
    }
    return 0;
}
